class Solution {
public:
    int countPairs(vector<int>& nums, int low, int high) {
        int count = 0;
        for (int i = 0; i < nums.size(); i++) {
            for (int j = i + 1; j < nums.size(); j++) {
                int xorResult = nums[i] ^ nums[j];
                if (xorResult >= low && xorResult <= high) {
                    count++;
                }
            }
        }
        return count;
    }
};
